                        uint16_t base = (uint16_t)(si * 4u);
                        uint8_t sy = comp->oam[(uint16_t)(base + 0u)];
                        uint8_t tile = comp->oam[(uint16_t)(base + 1u)];
                        uint8_t attr = comp->oam[(uint16_t)(base + 2u)];
                        uint8_t sx = comp->oam[(uint16_t)(base + 3u)];
