                    uint8_t p2_env = (comp->apu_p2_constant != 0u) ? comp->apu_p2_volume : comp->apu_p2_env_decay;
                    uint8_t n_env = (comp->apu_noise_constant != 0u) ? comp->apu_noise_volume : comp->apu_noise_env_decay;
